  ('judicial-57112235-moex-00347', 'judicial-57112235', 'judicial-57112235-moex-112-cc138910', 'sub-judicial-57112235-02', NULL, 'single_choice', '有關慢性習慣犯（ChronicOffender）之敘述，下列何者正確？', '["多被判處短期自由刑", "極易受矯正感化", "係指少數人觸犯大多數比例的犯罪", "常觸犯妨害風化罪"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "7f1c00302ebe", "answer_pdf_sha1": "e2de2a390f35", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0703", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪學概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00348', 'judicial-57112235', 'judicial-57112235-moex-112-cc138910', 'sub-judicial-57112235-02', NULL, 'single_choice', '對於自陳報告獲取犯罪資料的敘述，下列何者錯誤？', '["自陳報告是彌補官方統計缺失的方法之一", "自陳報告大多採抽樣問卷調查方式行之", "自陳報告傾向於詮釋犯罪情節較輕微之犯行", "自陳報告所得的犯罪資料，不受當事人記憶影響"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "7f1c00302ebe", "answer_pdf_sha1": "e2de2a390f35", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0703", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪學概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00349', 'judicial-57112235', 'judicial-57112235-moex-112-cc138910', 'sub-judicial-57112235-02', NULL, 'single_choice', '有關犯罪被害調查的敘述，下列何者錯誤？', '["犯罪被害調查能彌補官方統計中有關犯罪黑數的問題", "犯罪被害調查只能被解釋為一種對可能已發生犯罪的估計量", "犯罪被害者記憶上的不正確係被害調查的重大缺陷之一", "犯罪被害調查能針對所有犯罪類型進行調查"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "7f1c00302ebe", "answer_pdf_sha1": "e2de2a390f35", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0703", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪學概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00350', 'judicial-57112235', 'judicial-57112235-moex-112-cc138910', 'sub-judicial-57112235-02', NULL, 'single_choice', '龍布羅梭（CesareLombroso）在犯罪學的發展歷史中，是一位非常重要的人物。下列敘述何者錯誤？', '["屬於犯罪學古典學派的代表人物之一", "和費利（EnricoFerri）及加洛法洛（RoffaellaGarofalo），被稱為義大利學派", "提出「生來犯罪人」的觀點，認為個體因為具有某些特殊的生理因素，導致他們從事犯罪行為", "龍布羅梭在晚期的著作中，認為有些人犯罪是受到社會環境的影響"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "7f1c00302ebe", "answer_pdf_sha1": "e2de2a390f35", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0703", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪學概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00351', 'judicial-57112235', 'judicial-57112235-moex-112-cc138910', 'sub-judicial-57112235-02', NULL, 'single_choice', '社會學家安格紐（RobertAgnew）於1992年提出一般化緊張理論（GeneralStrainTheory），其嘗試 解釋遭遇到緊張及壓力的個人容易觸犯犯罪行為，而安格紐認為壓力有四種來源，下列何者錯誤？', '["負面刺激之移除", "期望與成就之差距", "正向價值刺激之移除", "未達正向價值之目標"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "7f1c00302ebe", "answer_pdf_sha1": "e2de2a390f35", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0703", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪學概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00352', 'judicial-57112235', 'judicial-57112235-moex-112-cc138910', 'sub-judicial-57112235-02', NULL, 'single_choice', '西元1764年出版之《犯罪與刑罰》（CrimeandPunishments），成為當時刑法之基本理論，對日後 刑法改革與犯罪學發展有很大影響，其作者為：', '["貝加利亞（Beccaria）", "龍布羅梭（Lombroso）", "加洛法洛（Garofalo）", "費利（Ferri）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "7f1c00302ebe", "answer_pdf_sha1": "e2de2a390f35", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0703", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪學概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00353', 'judicial-57112235', 'judicial-57112235-moex-112-cc138910', 'sub-judicial-57112235-02', NULL, 'single_choice', '美國犯罪學學者葛魯克夫婦（SheldonandEleaneorGlueck）曾對500名少年犯與相同環境、相同 年齡之500名非少年犯做比較研究，認為少年犯與非少年犯有以下顯著差異，下列敘述何者錯誤？', '["少年犯在氣質上經常表現侵略攻擊性及破壞性", "少年犯在情感或態度上經常表現敵對或挑釁", "少年犯心理上喜歡做間接的學習", "少年犯多是在不適當管教之下長大"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "7f1c00302ebe", "answer_pdf_sha1": "e2de2a390f35", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0703", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪學概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00354', 'judicial-57112235', 'judicial-57112235-moex-112-cc138910', 'sub-judicial-57112235-02', NULL, 'single_choice', '關於犯罪社會學中芝加哥學派（TheChicagoSchool），蕭氏及馬凱（ShawandMckay）對少年犯罪 的研究結論中，下列敘述何者錯誤？', '["某些地區少年犯特別多而形成少年犯罪地帶", "少年犯罪集中於靠近市區之高房價地區，離市區愈遠愈多", "小孩逃學率高的地區，少年犯較多", "市中心的少年犯罪行為發生率較高，而愈向郊區則愈低"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "7f1c00302ebe", "answer_pdf_sha1": "e2de2a390f35", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0703", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪學概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00355', 'judicial-57112235', 'judicial-57112235-moex-112-cc138910', 'sub-judicial-57112235-02', NULL, 'single_choice', '根據學者Bartollas（1985）的觀點，認為犯罪矯正有三大主流哲學，下列何者不是其所提及的模式？', '["理性選擇模式（RationalChoiceModel）", "矯治模式（RehabilitationModel）", "懲罰模式（PunishmentModel）", "正義模式（JusticeModel）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "7f1c00302ebe", "answer_pdf_sha1": "e2de2a390f35", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0703", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪學概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00356', 'judicial-57112235', 'judicial-57112235-moex-112-cc138910', 'sub-judicial-57112235-02', NULL, 'single_choice', '有關梅爾頓（RobertMerton）提出的無規範理論（亂迷理論，TheoryofAnomie），下列敘述何者 正確？', '["梅爾頓認為每一個社會及文化均由物質目標和手段所組成", "根據目標與手段間不同的組成，提出守法者（Conformity）、標新者（Innovation）、精通儀式者 （Ritualism）、無助者（Helplessness）及反叛者（Rebellion）等適應模式", "梅爾頓認為犯罪是手段無規範（手段亂迷）的結果，而涂爾幹（EmileDurkheim）則認為是目標 無規範（目標亂迷）的結果", "標新者（Innovation），是指其內心有不法之企圖、目的，但外顯的行為卻是遵循固有的文化及 規範"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "7f1c00302ebe", "answer_pdf_sha1": "e2de2a390f35", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "207", "s": "0703", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪學概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL)
